const t=document.querySelectorAll("section"),i=new IntersectionObserver(e=>{e.forEach(s=>{s.isIntersecting?(s.target.classList.add("section-visible"),s.target.classList.remove("section-exit")):s.target.classList.contains("section-visible")&&(s.target.classList.add("section-exit"),s.target.classList.remove("section-visible"))})},{threshold:.12,rootMargin:"0px 0px -60px 0px"});t.forEach(e=>i.observe(e));
